interface NewPostBody {
  title?: string;
  content?: string;
}

const samplePosts: Post[] = [
  { id: 1, title: 'First Post', content: 'This is the first post' },
  { id: 2, title: 'Second Post', content: 'This is the second post' },
];

export async function GET(): Promise<Response> {
  return Response.json(samplePosts);
}

export async function POST(request: NextRequest): Promise<Response> {
  const body: NewPostBody = await request.json();

  if (!body.title || !body.content) {
    return Response.json(
      { error: 'Title and content are required' },
      { status: 400 }
    );
  }

  const newPost: Post = {
    id: Date.now(),
    title: body.title,
    content: body.content,
  };

  return Response.json(newPost, { status: 201 });
}

interface Post {
  id: number;
  title: string;
  content: string;
  createdAt?: string;
  updatedAt?: string;
}

interface UpdatePostBody {
  title?: string;
  content?: string;
}

export async function GET(
  _request: Request,
  context: { params: Promise<{ id: string }> }
): Promise<Response> {
  const { id } = await context.params;

  const post: Post = {
    id: parseInt(id),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return Response.json(post);
}

export async function PUT(
  request: Request,
  context: { params: Promise<{ id: string }> }
): Promise<Response> {
  const { id } = await context.params;
  const body: UpdatePostBody = await request.json();

  const updatedPost: Post = {
    id: parseInt(id),
    title: body.title || `Post ${id}`,
    content: body.content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return Response.json(updatedPost);
}

export async function DELETE(
  _request: Request,
  context: { params: Promise<{ id: string }> }
): Promise<Response> {
  const { id } = await context.params;

  return Response.json({ message: `Post ${id} deleted successfully` });
}
